// === src\lib\sounds.js ===
// 背景音乐 & 音效：使用 Web Audio API 生成简单的复古 8-bit 旋律
let audioCtx = null;
let bgGain = null;
let bgNodes = [];
let musicPlaying = false;

function getCtx() {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  return audioCtx;
}

// 简单的音符频率 (Hz)
const N = {
  C4: 261.63, D4: 293.66, E4: 329.63, F4: 349.23, G4: 392.00, A4: 440.00, B4: 493.88,
  C5: 523.25, D5: 587.33, E5: 659.25, F5: 698.46, G5: 783.99, A5: 880.00, B5: 987.77,
  REST: 0
};

// 简单可爱的旋律（小星星变奏）
const MELODY = [
  [N.C5, 0.4], [N.C5, 0.4], [N.G5, 0.4], [N.G5, 0.4], [N.A5, 0.4], [N.A5, 0.4], [N.G5, 0.8],
  [N.F5, 0.4], [N.F5, 0.4], [N.E5, 0.4], [N.E5, 0.4], [N.D5, 0.4], [N.D5, 0.4], [N.C5, 0.8],
  [N.G5, 0.4], [N.G5, 0.4], [N.F5, 0.4], [N.F5, 0.4], [N.E5, 0.4], [N.E5, 0.4], [N.D5, 0.8],
  [N.G5, 0.4], [N.G5, 0.4], [N.F5, 0.4], [N.F5, 0.4], [N.E5, 0.4], [N.E5, 0.4], [N.D5, 0.8],
  [N.C5, 0.4], [N.C5, 0.4], [N.G5, 0.4], [N.G5, 0.4], [N.A5, 0.4], [N.A5, 0.4], [N.G5, 0.8],
  [N.F5, 0.4], [N.F5, 0.4], [N.E5, 0.4], [N.E5, 0.4], [N.D5, 0.4], [N.D5, 0.4], [N.C5, 0.8]
];

let melodyIdx = 0;
let bgTimeout = null;

function playNote(freq, duration) {
  if (freq === N.REST || !audioCtx) return;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.type = "square";
  osc.frequency.value = freq;
  gain.gain.setValueAtTime(0, audioCtx.currentTime);
  gain.gain.linearRampToValueAtTime(0.05, audioCtx.currentTime + 0.02);
  gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
  osc.connect(gain);
  gain.connect(bgGain);
  osc.start();
  osc.stop(audioCtx.currentTime + duration);
}

function scheduleMelody() {
  if (!musicPlaying) return;
  const [freq, dur] = MELODY[melodyIdx % MELODY.length];
  playNote(freq, dur * 0.9);
  melodyIdx++;
  bgTimeout = setTimeout(scheduleMelody, dur * 1000);
}

function startMusic() {
  if (musicPlaying) return;
  const ctx = getCtx();
  if (ctx.state === "suspended") ctx.resume();
  bgGain = ctx.createGain();
  bgGain.gain.value = 0.15;
  bgGain.connect(ctx.destination);
  musicPlaying = true;
  scheduleMelody();
}

function stopMusic() {
  musicPlaying = false;
  if (bgTimeout) clearTimeout(bgTimeout);
  if (bgGain) {
    bgGain.disconnect();
    bgGain = null;
  }
}

function isMusicPlaying() { return musicPlaying; }

function setVolume(v) {
  if (bgGain) bgGain.gain.value = v * 0.3;
}

// 短音效
function playSfx(type) {
  const ctx = getCtx();
  if (ctx.state === "suspended") ctx.resume();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.connect(gain);
  gain.connect(ctx.destination);
  if (type === "click") {
    osc.frequency.value = 800;
    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.08);
    osc.start(); osc.stop(ctx.currentTime + 0.08);
  } else if (type === "success") {
    osc.frequency.setValueAtTime(523, ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(784, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(0.15, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    osc.start(); osc.stop(ctx.currentTime + 0.25);
  } else if (type === "fail") {
    osc.frequency.setValueAtTime(400, ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(200, ctx.currentTime + 0.2);
    gain.gain.setValueAtTime(0.12, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    osc.start(); osc.stop(ctx.currentTime + 0.25);
  } else if (type === "win") {
    [523, 659, 784, 1047].forEach((f, i) => {
      const o = ctx.createOscillator();
      const g = ctx.createGain();
      o.type = "square";
      o.frequency.value = f;
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.1);
      g.gain.linearRampToValueAtTime(0.12, ctx.currentTime + i * 0.1 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.1 + 0.2);
      o.connect(g); g.connect(ctx.destination);
      o.start(ctx.currentTime + i * 0.1);
      o.stop(ctx.currentTime + i * 0.1 + 0.25);
    });
  } else if (type === "unlock") {
    [659, 784, 988, 1175].forEach((f, i) => {
      const o = ctx.createOscillator();
      const g = ctx.createGain();
      o.frequency.value = f;
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.06);
      g.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.06 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.06 + 0.15);
      o.connect(g); g.connect(ctx.destination);
      o.start(ctx.currentTime + i * 0.06);
      o.stop(ctx.currentTime + i * 0.06 + 0.18);
    });
  }
}

// === src\lib\storage.js ===
// localStorage 持久化层
const KEYS = {
  PROFILE: "td_profile",
  HISTORY: "td_history",
  STATS: "td_stats",
  ACHIEVEMENTS: "td_achievements",
  SETTINGS: "td_settings"
};

function getProfile() {
  try { return JSON.parse(localStorage.getItem(KEYS.PROFILE) || "{}"); } catch (e) { return {}; }
}
function setProfile(p) {
  localStorage.setItem(KEYS.PROFILE, JSON.stringify(p));
}

function getHistory() {
  try { return JSON.parse(localStorage.getItem(KEYS.HISTORY) || "[]"); } catch (e2) { return []; }
}
function addHistory(entry) {
  const h = getHistory();
  h.unshift({ ...entry, at: Date.now() });
  localStorage.setItem(KEYS.HISTORY, JSON.stringify(h.slice(0, 50)));
}

function getStats() {
  try { return JSON.parse(localStorage.getItem(KEYS.STATS) || "{}"); } catch (e3) { return {}; }
}
function updateStats(gameType, win) {
  const s = getStats();
  s[gameType] = s[gameType] || { played: 0, won: 0 };
  s[gameType].played += 1;
  if (win) s[gameType].won += 1;
  s.totalPlayed = (s.totalPlayed || 0) + 1;
  s.totalWins = (s.totalWins || 0) + (win ? 1 : 0);
  localStorage.setItem(KEYS.STATS, JSON.stringify(s));
  return s;
}

function getAchievements() {
  try { return JSON.parse(localStorage.getItem(KEYS.ACHIEVEMENTS) || "[]"); } catch (e4) { return []; }
}
function unlockAchievement(id) {
  const a = getAchievements();
  if (a.find(x => x.id === id)) return false;
  a.push({ id, at: Date.now() });
  localStorage.setItem(KEYS.ACHIEVEMENTS, JSON.stringify(a));
  return true;
}

function getSettings() {
  try { return JSON.parse(localStorage.getItem(KEYS.SETTINGS) || "{}"); } catch (e5) { return {}; }
}
function saveSettings(s) {
  const cur = getSettings();
  const merged = { ...cur, ...s };
  localStorage.setItem(KEYS.SETTINGS, JSON.stringify(merged));
  return merged;
}

function clearAll() {
  Object.values(KEYS).forEach(k => localStorage.removeItem(k));
}

